def position_entities_for_bug_scenario(game, player_pos, monster_pos):
    """Position player and monsters for a specific bug scenario."""
    game.player.x, game.player.y = player_pos

    # Find and position a monster
    for entity in game.entities:
        if entity.name == "Goblin":
            entity.x, entity.y = monster_pos
            return entity
    return None

def set_entity_stats_for_edge_case(entity, hp=None, power=None, defense=None):
    """Set entity stats to specific values for edge case testing."""
    if hp is not None:
        entity.hp = hp
        entity.max_hp = hp
    if power is not None:
        entity.power = power
    if defense is not None:
        entity.defense = defense
    return entity

def execute_action_and_verify(game, action, expected_state_change=None):
    """Execute an action and optionally verify state changes."""
    initial_state = {
        'player_x': game.player.x,
        'player_y': game.player.y,
        'player_hp': game.player.hp,
    }

    game.process_action(action)

    if expected_state_change:
        for key, expected_value in expected_state_change.items():
            actual_value = getattr(game.player, key, None)
            assert actual_value == expected_value, f"Expected {key}={expected_value}, got {actual_value}"

    return initial_state
